// Mixin that controls the text style
@mixin sassy-button-text-style($base-color, $second-color, $text-color, $text-style: "inset")
  $text-lightness: lightness($text-color)
  $text-color-shift: 0
  $diff : lightness($base-color) - lightness($second-color)

  @if $diff > 40
    $text-color-shift: 35  + ($diff/10)
  @else if $diff > 18
    $text-color-shift: 30  + ($diff/10)
  @else
    $text-color-shift: 25  + ($diff/10)

  color: $text-color

  @if $text-style == "inset"
    @if $text-lightness < 50
      @include text-shadow(lighten($second-color, ($text-color-shift/1.5)) 0 1px 0)
    @else
      @include text-shadow(darken($base-color, $text-color-shift) 0 -1px 0)
  @if $text-style == "raised"
    @if $text-lightness < 50
      @include text-shadow(lighten($second-color, ($text-color-shift/1.5)) 0 -1px 0)
    @else
      @include text-shadow(darken($base-color, $text-color-shift) 0 1px 0)

@function powerNumber($number, $exp)
  $value: 1
  @if $exp > 0
    @for $i from 1 through $exp
      $value: $value * $number
  @else if $exp < 0
    @for $i from 1 through -$exp
      $value: $value / $number
  @return $value

@function colorLuminance($color)
  $color-rgb: ('red': red($color),'green': green($color),'blue': blue($color))
  @each $name, $value in $color-rgb
    $adjusted: 0
    $value: $value / 255
    @if $value < 0.03928
      $value: $value / 12.92
    @else
      $value: ($value + .055) / 1.055
      $value: powerNumber($value, 2)
    $color-rgb: map-merge($color-rgb, ($name: $value))
  @return (map-get($color-rgb, 'red') * .2126) + (map-get($color-rgb, 'green') * .7152) + (map-get($color-rgb, 'blue') * .0722)

@function closestEvenNumber($number)
  @if ($number % 2 == 0px)
    @return $number
  @else
    @return ($number + 1px)

@function findColorInvert($color)
  @if (colorLuminance($color) > 0.8)
    @return rgba(black, 0.5)
  @else
    @return white

@use '../../styles/tools'
@use './variables' as *

@include tools.layer('components')
  .v-system-bar
    align-items: center
    display: flex
    flex: $system-bar-flex
    height: $system-bar-height
    justify-content: $system-bar-justify-content
    max-width: 100%
    padding-inline: $system-bar-padding-x
    position: relative
    text-align: $system-bar-text-align
    width: 100%

    .v-icon
      opacity: $system-bar-icon-opacity

    @include tools.elevation($system-bar-elevation)
    @include tools.position($system-bar-positions)
    @include tools.theme($system-bar-theme...)
    @include tools.typography($system-bar-typography...)

    &--rounded
      @include tools.rounded($system-bar-border-radius)

    &--window
      height: $system-bar-window-height

    &:not(.v-system-bar--absolute)
      padding-inline-end: calc(var(--v-scrollbar-offset) + #{$system-bar-padding-x})

